BFS(G, s):
  for each u in G.V-{s}:
    u.color=WHITE, u.d=∞, u.π=NIL
  s.color=GRAY, s.d=0, s.π=NIL
  Q = empty queue
  ENQUEUE(Q, s)
  while Q ≠ empty:
    u = DEQUEUE(Q)
    for each v in G.Adj[u]:
      if v.color==WHITE:
        v.color=GRAY, v.d=u.d+1, v.π=u
        ENQUEUE(Q, v)
    u.color=BLACK

DFS(G):
  for each u: u.color=WHITE, u.π=NIL
  time=0
  for each u in G.V:
    if u.color==WHITE: DFS-VISIT(G,u)

DFS-VISIT(G, u):
  time++, u.d=time, u.color=GRAY
  for each v in G.Adj[u]:
    if v.color==WHITE:
      v.π=u
      DFS-VISIT(G,v)
  u.color=BLACK, time++, u.f=time

DIJKSTRA(G, w, s):
  INITIALIZE-SINGLE-SOURCE(G, s)
  S = empty set
  Q = MIN-PRIORITY-QUEUE with all vertices
  while Q ≠ empty:
    u = EXTRACT-MIN(Q)
    S = S ∪ {u}
    for each v in G.Adj[u]:
      RELAX(u, v, w)

RELAX(u, v, w):
  if d[v] > d[u] + w(u,v):
    d[v] = d[u] + w(u,v)
    π[v] = u

kruskal.pseudocode:
KRUSKAL(G, w):
  A = empty set
  for each vertex v: MAKE-SET(v)
  sort edges by weight
  for each edge (u,v) in sorted order:
    if FIND-SET(u) ≠ FIND-SET(v):
      A = A ∪ {(u,v)}
      UNION(u,v)
  return A

