PRIM(G, w, r):
  for each u: key[u]=∞, π[u]=NIL
  key[r] = 0
  Q = MIN-HEAP with all vertices
  while Q ≠ empty:
    u = EXTRACT-MIN(Q)
    for each v in G.Adj[u]:
      if v in Q and w(u,v) < key[v]:
        π[v]=u, key[v]=w(u,v)

